import { Flex, ModalProps } from '@chakra-ui/react';
import { IActionPage } from '@domain/actionPages';
import { useGetAccount } from '@state/accounts';
import { useBulkUpdateActionPages } from '@state/action_pages';
import { FormDateTimeControl } from '@ui/components/formControls/DateTimeControl/FormDateTimeControl';
import { useEnhancedForm } from '@ui/components/formControls/Form/hooks/useEnhancedForm';
import { FormTextAreaControl } from '@ui/components/formControls/TextAreaControl/FormTextAreaControl';
import { DestructiveConfirmationModal } from '@ui/components/molecules/DestructiveConfirmationModal';
import { Paragraph } from '@ui/components/typography';
import { withLazyMount } from '@utils/withLazyMount';
import { addDays } from 'date-fns';
import { zonedTimeToUtc } from 'date-fns-tz';
import { useCallback, useEffect, useMemo } from 'react';
import { FormProvider } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { Row } from 'react-table';

type BulkSchedulePauseFormShape = {
  pauseEndAt?: Date | null;
  pauseStartAt?: Date | null;
  pausedMessage?: string;
};

type BulkSchedulePauseConfirmationModalProps = Pick<ModalProps, 'isOpen' | 'onClose'> & {
  isAllSelected?: boolean;
  selectedRows: Row<IActionPage>[] | undefined;
};

export const BulkSchedulePauseConfirmationModal = withLazyMount(
  ({ isAllSelected, isOpen, onClose, selectedRows }: BulkSchedulePauseConfirmationModalProps) => {
    const { t } = useTranslation(['common', 'actionPages']);
    const { currentAccount } = useGetAccount();
    const timeZone = currentAccount?.timeZone;

    const form = useEnhancedForm<BulkSchedulePauseFormShape>({
      enableReinitialize: true,
      initialValues: {
        pausedMessage: t('actionPages:schedulePause.modal.defaultMessage'),
        pauseEndAt: null,
        pauseStartAt: null,
      },
    });

    const { bulkUpdateActionPages, isLoading: isUpdating } = useBulkUpdateActionPages();
    const { handleSubmit, setValue, watch } = form;
    const pauseStartAt = watch('pauseStartAt');
    const pauseEndAt = watch('pauseEndAt');

    const minPauseEndAt = useMemo(
      () => (pauseStartAt ? addDays(pauseStartAt, 1) : new Date()),
      [pauseStartAt]
    );

    useEffect(() => {
      if (pauseEndAt && pauseStartAt && pauseEndAt < pauseStartAt) {
        setValue('pauseEndAt', addDays(pauseStartAt, 1));
      }
    }, [pauseEndAt, pauseStartAt, setValue]);

    const internalOnSubmit = useCallback(
      async (values: BulkSchedulePauseFormShape) => {
        await bulkUpdateActionPages({
          all: isAllSelected ? true : undefined,
          ids: isAllSelected ? undefined : selectedRows?.map((row) => row.original.id),
          pausedMessage: values.pausedMessage,
          pauseEndAt:
            values.pauseEndAt && timeZone
              ? zonedTimeToUtc(values.pauseEndAt, timeZone).toISOString()
              : (values.pauseEndAt?.toISOString() ?? null),
          pauseStartAt:
            values.pauseStartAt && timeZone
              ? zonedTimeToUtc(values.pauseStartAt, timeZone).toISOString()
              : (values.pauseStartAt?.toISOString() ?? null),
        });

        onClose();
      },
      [bulkUpdateActionPages, isAllSelected, onClose, selectedRows, timeZone]
    );

    const onSubmit = useMemo(
      () => handleSubmit(internalOnSubmit),
      [handleSubmit, internalOnSubmit]
    );

    return (
      <DestructiveConfirmationModal
        buttonLayout="row-reverse"
        cancelButtonText={t('common:button.cancel')}
        colorScheme="blue"
        confirmButtonText={t('actionPages:schedulePause.modal.action')}
        header={
          isAllSelected
            ? t('actionPages:schedulePause.modal.titleAll')
            : t('actionPages:schedulePause.modal.title', { count: selectedRows?.length })
        }
        isLoading={isUpdating}
        isOpen={isOpen}
        onCancel={onClose}
        onConfirm={onSubmit}
        size="md"
      >
        <FormProvider {...form}>
          <form autoComplete="off" id="schedule-pause-form" onSubmit={onSubmit}>
            <Flex flexDirection="column" gap={2}>
              <Paragraph variant="regular">
                {t('actionPages:schedulePause.modal.description', { count: selectedRows?.length })}
              </Paragraph>
              <Flex flexDirection="row">
                <FormDateTimeControl
                  // `mr` necessary to avoid react-date-picker hidden element from affecting spacing
                  formControlProps={{ mr: 1 }}
                  label={t('actionPages:schedulePause.modal.offDate')}
                  minDate={new Date()}
                  name="pauseStartAt"
                  type="fullDate"
                  variant="permafloating"
                />
                <FormDateTimeControl
                  // `ml` necessary to avoid react-date-picker hidden element from affecting spacing
                  formControlProps={{ ml: 1 }}
                  label={t('actionPages:schedulePause.modal.onDate')}
                  minDate={minPauseEndAt}
                  name="pauseEndAt"
                  type="fullDate"
                  variant="permafloating"
                />
              </Flex>
              <FormTextAreaControl
                debounce={400}
                mb={0}
                name="pausedMessage"
                placeholder={t('common:message')}
                variant="outline"
              />
            </Flex>
          </form>
        </FormProvider>
      </DestructiveConfirmationModal>
    );
  }
);

